// Obtener datos del paciente
const paciente = $("Obtener o Crear Paciente").first().json;
const turnos = $("Consultar Turnos del Paciente").all().map(i => i.json);
const recetas = $("Consultar Recetas Activas").all().map(i => i.json).filter(r => r.estado === 'activa' || r.estado === 'pendiente');
const extraer = $("Extraer Datos").first().json;

// Helper para escapar strings SQL
const esc = (s) => (s || '').replace(/'/g, "''");

// Formatear turnos y recetas para el prompt
const turnosTexto = turnos.length > 0
  ? turnos.map(t => `- ${new Date(t.fecha_hora).toLocaleDateString("es-AR", {weekday: "long", day: "numeric", month: "long"})} a las ${(t.hora_inicio || '').substring(0,5)} con Dr. ${t.medico_nombre} (${t.motivo || 'consulta'})`).join('\n')
  : 'No tiene turnos próximos.';

const recetasTexto = recetas.length > 0
  ? recetas.map(r => `- ${r.medicamento} ${r.dosis || ''} (vence: ${(r.created_at || "", 0, 10) || 'N/A'})`).join('\n')
  : 'No tiene recetas activas.';

const fechaActual = new Date().toLocaleDateString('es-AR', { year: 'numeric', month: 'long', day: 'numeric' });

// System prompt completo para el AI Agent
const systemPrompt = `Sos el asistente virtual del Consultorio Médico. Atendés pacientes por WhatsApp.
Fecha actual: ${fechaActual}

=== DATOS DEL PACIENTE ===
Nombre: ${paciente.nombre || extraer.profileName}
Teléfono: ${paciente.telefono}

=== TURNOS PRÓXIMOS ===
${turnosTexto}

=== RECETAS ACTIVAS ===
${recetasTexto}

=== INSTRUCCIONES ===
Respondé en español argentino, con tono cálido y profesional. Sé breve y resolutivo.

REGLAS:
- NO inventes diagnósticos
- NO recetes medicamentos ni recomiendes tratamientos
- SIEMPRE derivá urgencias al médico
- Horarios: "Lunes a viernes de 8 a 20hs, sábados de 9 a 13hs"
- Urgencias: "Si es una emergencia, dirigite a la guardia o llamá al 107"

CUANDO EL PACIENTE PIDA UNA ACCIÓN (crear/cancelar turno, renovar receta):
Respondé de forma natural, y al final agregá SOLAMENTE:
###ACCION###
{"tipo": "crear_turno", "data": {"fecha": "YYYY-MM-DD", "hora": "HH:MM", "motivo": "..."}}
###FIN###

Tipos: crear_turno | cancelar_turno | solicitar_receta | notificar_urgencia
NO incluyas ###ACCION### si solo respondés una consulta o saludo.`;

const contexto = {
  paciente: {
    id: paciente.id,
    telefono: paciente.telefono,
    nombre: paciente.nombre || extraer.profileName,
    apellido: paciente.apellido
  },
  turnosProximos: turnos.map(t => ({
    id: t.id, fecha: t.fecha_hora, hora: (t.hora_inicio || '').substring(0,5),
    medico: t.medico_nombre, especialidad: t.especialidad,
    motivo: t.motivo, estado: t.estado
  })),
  recetasActivas: recetas.map(r => ({
    id: r.id, medicamento: r.medicamento, dosis: r.dosis,
    indicaciones: r.indicaciones, estado: r.estado
  })),
  systemPrompt: systemPrompt,
  phone: extraer.phone,
  message: extraer.message,
  profileName: extraer.profileName,
  twilioSid: extraer.twilioSid,
  toNumber: extraer.toNumber,
  fromNumber: extraer.fromNumber
};

return [contexto];

// Obtener la respuesta del agente
const rawText = $input.first().json.agentOutput || $input.first().json.output || '';

// Datos de contexto
const ctx = $("Construir Contexto Paciente").first().json;
const pacienteId = $("Obtener o Crear Paciente").first().json.id;
const extraer = $("Extraer Datos").first().json;

// Helper para escapar SQL (protección contra inyección)
// NOTA: En producción considerar migrar esto a nodos PostgreSQL con queryParams
const esc = (s) => {
  if (!s) return '';
  return String(s)
    .replace(/'/g, "''")         // Escapar comillas simples (SQL injection)
    .replace(/\\/g, '\\\\')  // Escapar backslashes
    .replace(/\0/g, '')          // Eliminar null bytes
    .replace(/\x1a/g, '');       // Eliminar caracteres de control
};

// Buscar acción estructurada
const actionMatch = rawText.match(/###ACCION###\n([\s\S]*?)\n###FIN###/);
let accion = null;
let textoLimpio = rawText;

if (actionMatch) {
  try {
    accion = JSON.parse(actionMatch[1].trim());
    textoLimpio = rawText.replace(/###ACCION###[\s\S]*?###FIN###/, '').trim();
  } catch (e) { accion = null; }
}

// Construir SQL para guardar conversación
const sqlGuardar = `INSERT INTO mensajes (conversacion_id, rol, contenido, tipo, twilio_sid, n8n_execution_id) VALUES ((SELECT id FROM conversaciones WHERE paciente_id = ${pacienteId} AND estado = 'activa' LIMIT 1), 'paciente', '${esc(extraer.message)}', 'texto', '${esc(extraer.twilioSid)}', '${$execution.id}'); INSERT INTO mensajes (conversacion_id, rol, contenido, tipo, n8n_execution_id) VALUES ((SELECT id FROM conversaciones WHERE paciente_id = ${pacienteId} AND estado = 'activa' LIMIT 1), 'asistente', '${esc(textoLimpio)}', 'texto', '${$execution.id}');`;

// Construir SQL para log
const sqlLog = `INSERT INTO workflow_logs (workflow_id, workflow_name, execution_id, nivel, mensaje) VALUES ('${$execution.id}', 'WhatsApp Agent', '${$execution.id}', 'info', '${esc('WhatsApp procesado por AI Agent. Paciente: ' + (pacienteId || '') + ' | Respuesta: ' + textoLimpio.substring(0, 100))}');`;

// Construir SQL para acción pendiente (si aplica)
let sqlAccion = null;
if (accion) {
  sqlAccion = `INSERT INTO workflow_logs (workflow_id, workflow_name, execution_id, nivel, mensaje) VALUES ('${$execution.id}', 'WhatsApp Agent', '${$execution.id}', '${esc(accion.tipo || 'accion')}', '${esc('ACCION PENDIENTE: ' + JSON.stringify(accion))}');`;
}

// Output unificado
return [{
  responseText: textoLimpio,
  tieneAccion: accion !== null,
  accionTipo: accion ? accion.tipo : null,
  accionData: accion ? accion.data : null,
  sqlGuardar: sqlGuardar,
  sqlLog: sqlLog,
  sqlAccion: sqlAccion,
  // Preservar datos para Twilio
  toNumber: ctx.toNumber,
  fromNumber: ctx.fromNumber,
  profileName: ctx.profileName,
  pacienteId: pacienteId
}];
